import org.jsoup.Jsoup;
import org.jsoup.select.Elements;

public class test_debug {
    public static void main(String[] args) {
        try {
            System.out.println("Testing selector with commas...");
            String html = "<p name='1,2'>One</p><div>Two</div><ol><li>123</li><li>Text</li></ol>";
            org.jsoup.nodes.Document doc = Jsoup.parse(html);

            System.out.println("HTML: " + html);

            // Test first selector
            System.out.println("\nTesting selector [name=1,2]:");
            Elements ps = doc.select("[name=1,2]");
            System.out.println("Found elements: " + ps.size());
            for (int i = 0; i < ps.size(); i++) {
                System.out.println("  Element " + i + ": " + ps.get(i).toString());
            }

            // Test second selector
            System.out.println("\nTesting selector div, li:matches([0-9,]+):");
            Elements containers = doc.select("div, li:matches([0-9,]+)");
            System.out.println("Found elements: " + containers.size());
            for (int i = 0; i < containers.size(); i++) {
                System.out.println("  Element " + i + ": " + containers.get(i).tagName() + " - " + containers.get(i).text());
            }
        } catch (Exception e) {
            System.out.println("Exception occurred: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

